// 2026-05-07: Converted from non-streaming HTTP Request node. Same node_id,
// same connections - only the implementation moved from HTTP Request to Code
// + streaming. Anthropic was dropping idle long-poll connections at ~5-6 min
// for max_tokens=64000 scene segmentation. Streaming keeps the connection
// active via SSE deltas. Output shape matches the HTTP response:
//   { content: [{type:'text', text: fullText}] }
// so the downstream "Build Scenes Array" Code node consumes it unchanged.
// On error, returns { error: { message } } to mimic the prior HTTP node's
// onError=continueRegularOutput contract.

const input = $input.first().json;
const promptText = input.metadata_prompt || '';
const AK = $env.ANTHROPIC_API_KEY;

const sysPrompt = 'You are a scene segmentation and visual direction expert for YouTube documentaries. Always return valid JSON arrays only. No markdown, no explanation.';

async function streamingClaude() {
  const maxRetries = 3;
  const perAttemptMs = 12 * 60 * 1000;
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    const ac = new AbortController();
    let timedOut = false;
    const timer = setTimeout(function() { timedOut = true; try { ac.abort(); } catch(_) {} }, perAttemptMs);
    try {
      const body = {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 64000,
        system: sysPrompt,
        messages: [{ role: 'user', content: promptText }],
        stream: true
      };
      const r = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': AK,
          'anthropic-version': '2023-06-01',
          'anthropic-beta': 'output-128k-2025-02-19'
        },
        body: JSON.stringify(body),
        signal: ac.signal
      });
      if (r.status === 429) {
        clearTimeout(timer);
        console.log('Visual Assignment rate-limited (attempt ' + attempt + '/' + maxRetries + '), waiting 30s...');
        await new Promise(function(res) { setTimeout(res, 30000); });
        continue;
      }
      if (r.status === 529) {
        clearTimeout(timer);
        console.log('Visual Assignment API overloaded (attempt ' + attempt + '/' + maxRetries + '), waiting 15s...');
        await new Promise(function(res) { setTimeout(res, 15000); });
        continue;
      }
      if (!r.ok) {
        clearTimeout(timer);
        let errBody = '';
        try { errBody = await r.text(); } catch(_) {}
        throw new Error('Claude HTTP ' + r.status + ': ' + errBody.slice(0, 300));
      }
      const reader = r.body.getReader();
      const decoder = new TextDecoder();
      let buf = '';
      let fullText = '';
      let apiError = null;
      while (true) {
        const chunk = await reader.read();
        if (chunk.done) break;
        buf += decoder.decode(chunk.value, { stream: true });
        const lines = buf.split('\n');
        buf = lines.pop() || '';
        for (let i = 0; i < lines.length; i++) {
          const trimmed = lines[i].trim();
          if (!trimmed) continue;
          let dataStr = '';
          if (trimmed.indexOf('data: ') === 0) dataStr = trimmed.slice(6);
          else if (trimmed.indexOf('data:') === 0) dataStr = trimmed.slice(5);
          else continue;
          dataStr = dataStr.trim();
          if (!dataStr || dataStr === '[DONE]') continue;
          try {
            const ev = JSON.parse(dataStr);
            if (ev.type === 'content_block_delta' && ev.delta && typeof ev.delta.text === 'string') {
              fullText += ev.delta.text;
            } else if (ev.type === 'error' && ev.error) {
              apiError = ev.error;
            }
          } catch (_) { /* skip malformed event */ }
        }
      }
      clearTimeout(timer);
      if (apiError) throw new Error('Claude stream error: ' + JSON.stringify(apiError));
      if (!fullText || fullText.length < 50) {
        throw new Error('Claude returned empty/near-empty stream (' + fullText.length + ' chars)');
      }
      return fullText;
    } catch (e) {
      clearTimeout(timer);
      lastErr = e;
      const msg = (e && e.message) ? e.message : String(e);
      console.log('Visual Assignment attempt ' + attempt + '/' + maxRetries + ' failed: ' + (timedOut ? '12min timeout (abort fired)' : msg));
      if (attempt < maxRetries) {
        const base = Math.min(5000 * Math.pow(2, attempt - 1), 30000);
        const jitter = Math.floor(Math.random() * 3000);
        const wait = base + jitter;
        console.log('Retrying in ' + Math.round(wait/1000) + 's...');
        await new Promise(function(res) { setTimeout(res, wait); });
      }
    }
  }
  throw lastErr || new Error('Visual Assignment streamingClaude() failed after ' + maxRetries + ' attempts');
}

